"use strict";(globalThis.webpackChunkcybersec_kb=globalThis.webpackChunkcybersec_kb||[]).push([[7077],{426(e){e.exports=JSON.parse('{"tag":{"label":"tool","permalink":"/niebezpiecznik_szkolenie/pl/docs/tags/tool","allTagsPath":"/niebezpiecznik_szkolenie/pl/docs/tags","count":14,"items":[{"id":"tools/burp-suite","title":"Burp Suite","description":"Jedno zdanie: Proxy HTTP/HTTPS przechwytuj\u0105ce, modyfikuj\u0105ce i odtwarzaj\u0105ce \u017c\u0105dania sieciowe mi\u0119dzy przegl\u0105dark\u0105 a serwerem.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/burp-suite"},{"id":"theory/burp-suite","title":"Burp Suite \u2014 przechwytywanie HTTP","description":"Burp Suite to proxy typu man-in-the-middle, kt\xf3ry przechwytuje i modyfikuje ruch HTTP/S mi\u0119dzy przegl\u0105dark\u0105 a serwerem \u2014 jest to podstawowe narz\u0119dzie do testowania bezpiecze\u0144stwa aplikacji webowych.","permalink":"/niebezpiecznik_szkolenie/pl/docs/theory/burp-suite"},{"id":"tools/dnstwist","title":"dnstwist","description":"Jedno zdanie: Generuje permutacje domen (warianty typosquattingu) i sprawdza, czy s\u0105 zarejestrowane.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/dnstwist"},{"id":"tools/domxss-libs","title":"DOMPurify & escape-goat \u2014 Biblioteki obrony przed XSS","description":"Jedno zdanie: Biblioteki JavaScript po stronie klienta do bezpiecznego wstawiania tre\u015bci dostarczanych przez u\u017cytkownika do DOM \u2014 zapobieganie XSS na etapie wyj\u015bcia.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/domxss-libs"},{"id":"tools/git-dumper","title":"git-dumper","description":"Jedno zdanie: Pobiera wystawione repozytorium .git z serwera WWW, umo\u017cliwiaj\u0105c inspekcj\u0119 jego pe\u0142nej historii i zawarto\u015bci.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/git-dumper"},{"id":"tools/gobuster-dirbuster","title":"Gobuster / DirBuster","description":"Jedno zdanie: Przeszukuje metod\u0105 brute-force katalogi i pliki na serwerach WWW przy u\u017cyciu list s\u0142\xf3w, aby odkry\u0107 ukryt\u0105 zawarto\u015b\u0107.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/gobuster-dirbuster"},{"id":"tools/hashcat","title":"Hashcat","description":"Jedno zdanie: Narz\u0119dzie do \u0142amania skr\xf3t\xf3w hase\u0142 akcelerowane GPU, obs\u0142uguj\u0105ce dziesi\u0105tki typ\xf3w skr\xf3t\xf3w, w tym JWT, MD5, bcrypt i NTLM.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/hashcat"},{"id":"tools/http-toolkit","title":"HTTP Toolkit","description":"Jedno zdanie: Przechwytuje ruch HTTP ze szczeg\xf3lnym uwzgl\u0119dnieniem aplikacji mobilnych \u2014 zw\u0142aszcza Android przez ADB.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/http-toolkit"},{"id":"tools/hydra","title":"Hydra","description":"Jedno zdanie: Sieciowe narz\u0119dzie brute-force do atakowania formularzy logowania, SSH, FTP i innych us\u0142ug uwierzytelniania.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/hydra"},{"id":"tools/jwt-tool","title":"jwt_tool","description":"Jedno zdanie: Narz\u0119dzie Python do dekodowania, analizowania i atakowania token\xf3w JWT \u2014 obejmuje wszystkie g\u0142\xf3wne podatno\u015bci JWT.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/jwt-tool"},{"id":"tools/metasploit","title":"Metasploit","description":"Jedno zdanie: Framework do test\xf3w penetracyjnych z setkami gotowych exploit\xf3w dla znanych CVE w aplikacjach webowych i us\u0142ugach.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/metasploit"},{"id":"tools/nikto","title":"Nikto","description":"Jedno zdanie: Skaner podatno\u015bci serwera WWW, kt\xf3ry wykrywa b\u0142\u0119dne konfiguracje, pliki domy\u015blne, przestarza\u0142e oprogramowanie i niebezpieczne nag\u0142\xf3wki HTTP.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/nikto"},{"id":"tools/sqlmap","title":"sqlmap","description":"Jedno zdanie: Automatyczne narz\u0119dzie do wykrywania i exploitowania SQL injection, kt\xf3re mo\u017ce enumerowa\u0107 bazy danych i zrzuca\u0107 tabele.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/sqlmap"},{"id":"tools/traitor","title":"Traitor","description":"Jedno zdanie: Automatyczne narz\u0119dzie do eskalacji uprawnie\u0144 w Linuksie, kt\xf3re skanuje i exploituje powszechne wektory eskalacji po uzyskaniu dost\u0119pu do pow\u0142oki.","permalink":"/niebezpiecznik_szkolenie/pl/docs/tools/traitor"}],"unlisted":false}}')}}]);